/**
 * API service for handling API calls with environment-specific base URLs and retry logic
 */

// Determine the API base URL based on the environment
const getApiBaseUrl = () => {
  if (process.env.NODE_ENV === 'production') {
    // In production (Vercel), use the /api prefix
    return '/api';
  }
  // In development, use the local backend
  return 'http://localhost:5000';
};

const API_BASE_URL = getApiBaseUrl();

/**
 * Make a fetch request with proper base URL, error handling, and retry logic
 * @param {string} endpoint - API endpoint (starting with /)
 * @param {Object} options - Fetch options
 * @param {number} retries - Number of retries (default: 3)
 * @param {number} backoff - Backoff factor in ms (default: 300)
 * @returns {Promise} - Fetch promise
 */
export const fetchApi = async (endpoint, options = {}, retries = 3, backoff = 300) => {
  // Remove /api prefix if it's already in the endpoint and we're in production
  const apiEndpoint = process.env.NODE_ENV === 'production' && endpoint.startsWith('/api')
    ? endpoint
    : `${API_BASE_URL}${endpoint}`;
    
  console.log(`[API] Fetching: ${apiEndpoint} (${process.env.NODE_ENV} mode)`);
  
  try {
    const response = await fetch(apiEndpoint, {
      ...options,
      headers: {
        'Content-Type': 'application/json',
        ...(options.headers || {})
      }
    });
    
    // Log success
    console.log(`[API] Request completed with status ${response.status}: ${apiEndpoint}`);
    return response;
  } catch (error) {
    console.error(`[API] Request failed: ${apiEndpoint}`, error);
    
    // Retry logic
    if (retries > 0) {
      console.log(`[API] Retrying request (${retries} attempts left)...`);
      // Wait using exponential backoff
      await new Promise(resolve => setTimeout(resolve, backoff));
      // Retry with one less retry and increased backoff
      return fetchApi(endpoint, options, retries - 1, backoff * 2);
    }
    
    // No more retries, throw the error
    throw error;
  }
};

/**
 * Helper to check if the API is available
 * @returns {Promise<boolean>} - Whether the API is available
 */
export const isApiAvailable = async () => {
  try {
    const response = await fetchApi('/health', {}, 1);
    return response.ok;
  } catch (error) {
    console.error('[API] Health check failed:', error);
    return false;
  }
};

export default {
  fetchApi,
  isApiAvailable
};
